suspend fun parseLargePayload(items: List<String>): List<Result> {
    return buildList {
        items.forEachIndexed { index, item ->
            if (index % 100 == 0) currentCoroutineContext().ensureActive()
            add(parse(item))
        }
    }
}

val parent = viewModelScope.launch {
    launch { loadProfile() }
    launch { loadRecommendations() }
}

parent.cancel() // cả hai child nhận cancellation

private var searchJob: Job? = null

fun search(keyword: String) {
    searchJob?.cancel()
    searchJob = viewModelScope.launch {
        try {
            val result = repository.search(keyword)
            _uiState.value = UiState.Content(result)
        } catch (e: CancellationException) {
            throw e
        } catch (e: Throwable) {
            _uiState.value = UiState.Error(e.toUiMessage())
        }
    }
}

suspend fun collectSocketEvents() {
    val subscription = socket.subscribe()
    try {
        subscription.events.collect { handle(it) }
    } finally {
        subscription.close()
    }
}

